import React, { useState } from "react";
import axios from "axios";

function App() {
  const [resume, setResume] = useState("");
  const [job, setJob] = useState("");
  const [result, setResult] = useState(null);
  const [error, setError] = useState("");

  const analyze = async () => {
    try {
      const res = await axios.post("http://localhost:8000/analyze", {
        resume_text: resume,
        job_description: job,
      });
      setResult(res.data);
      setError("");
    } catch (err) {
      setError("Backend not connected.");
    }
  };

  return (
    <div style={{
      minHeight: "100vh",
      background: "linear-gradient(to right, #1e3c72, #2a5298)",
      color: "white",
      padding: "40px",
      fontFamily: "Segoe UI"
    }}>
      <h1 style={{ textAlign: "center", fontSize: "42px" }}>
        HireSense AI 🚀
      </h1>

      <div style={{ display: "flex", gap: "20px", marginTop: "30px" }}>
        <textarea
          placeholder="Paste Resume Here"
          rows="10"
          value={resume}
          onChange={(e) => setResume(e.target.value)}
          style={{
            flex: 1,
            padding: "15px",
            borderRadius: "10px",
            border: "none"
          }}
        />

        <textarea
          placeholder="Paste Job Description Here"
          rows="10"
          value={job}
          onChange={(e) => setJob(e.target.value)}
          style={{
            flex: 1,
            padding: "15px",
            borderRadius: "10px",
            border: "none"
          }}
        />
      </div>

      <div style={{ textAlign: "center", marginTop: "20px" }}>
        <button
          onClick={analyze}
          style={{
            padding: "12px 30px",
            borderRadius: "25px",
            border: "none",
            background: "#ff9800",
            fontSize: "18px",
            cursor: "pointer"
          }}
        >
          Analyze Resume
        </button>
      </div>

      {error && <p style={{ color: "yellow" }}>{error}</p>}

      {result && (
        <div style={{
          marginTop: "40px",
          background: "white",
          color: "black",
          padding: "20px",
          borderRadius: "15px"
        }}>
          <h2>Match Score: {result.match_score}%</h2>

          <div style={{
            height: "20px",
            background: "#ddd",
            borderRadius: "10px",
            overflow: "hidden",
            marginBottom: "20px"
          }}>
            <div style={{
              width: `${result.match_score}%`,
              background: "#4caf50",
              height: "100%"
            }}></div>
          </div>

          <h3>Missing Keywords:</h3>
          <ul>
            {result.missing_keywords.map((item, index) => (
              <li key={index}>{item}</li>
            ))}
          </ul>

          <p>{result.suggestion}</p>
        </div>
      )}
    </div>
  );
}

export default App;
